module watchdog_timer(
    input clk,
    input rst,
    input enable,
    output reg timeout
);
    reg [3:0] countdown; // 4-bit countdown for counting up to 10

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            countdown <= 0;
            timeout <= 0;
        end else if (enable) begin
            if (countdown < 10) begin
                countdown <= countdown + 1;
                timeout <= 0;
            end else begin
                timeout <= 1;
            end
        end
    end
endmodule
